// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract SellerRegistry {
    struct Seller {
        string aadhaar;
        string name;
        string email;
        string faddress;
        address owner;
    }

    mapping(string => Seller) public sellers;
    
    event SellerAdded(string indexed aadhaar, string name, address owner);

    function addSeller(
        string memory _aadhaar,
        string memory _name,
        string memory _email,
        string memory _address
    ) public {
        require(bytes(sellers[_aadhaar].aadhaar).length == 0, "Seller already exists");

        sellers[_aadhaar] = Seller({
            aadhaar: _aadhaar,
            name: _name,
            email: _email,
            faddress: _address,
            owner: msg.sender
        });

        emit SellerAdded(_aadhaar, _name, msg.sender);
    }

    function getSeller(string memory _aadhaar) public view returns (Seller memory) {
        return sellers[_aadhaar];
    }
}

contract FlatHouseRegistry {

    SellerRegistry public sellerRegistry;

    struct LocationInfo {
        string city;
        string area;
        string street;
    }

    struct HouseDetails {
        uint256 rent;
        uint256 advance;
        string imageUrl;
        string houseType;
        string houseNo;
    }

    struct FlatHouse {
        string sellerAadhaar;
        LocationInfo location;
        HouseDetails houseDetails;
        address owner;
    }

    mapping(string => FlatHouse) public flats;
    string[] public houseIds;
    
    event FlatHouseAdded(
        string indexed houseId,
        string sellerAadhaar,
        string houseType,
        uint256 rent,
        uint256 advance
    );

    // Connect to SellerRegistry contract
    constructor(address _sellerRegistryAddress) {
        sellerRegistry = SellerRegistry(_sellerRegistryAddress);
    }

    // Function to add flat/house details with less parameters
    function addFlatHouse(
        string memory _sellerAadhaar,
        string memory _city,
        string memory _area,
        string memory _street,
        uint256 _rent,
        uint256 _advance,
        string memory _imageUrl,
        string memory _houseType,
        string memory _houseNo
    ) public {
        // Ensure seller exists in SellerRegistry
        require(bytes(sellerRegistry.getSeller(_sellerAadhaar).aadhaar).length != 0, "Seller not registered");

        // Check if house already exists
        require(bytes(flats[_houseNo].houseDetails.houseNo).length == 0, "House ID already exists");

        // Create and store flat/house
        flats[_houseNo] = FlatHouse({
            sellerAadhaar: _sellerAadhaar,
            location: LocationInfo(_city, _area, _street),
            houseDetails: HouseDetails(_rent, _advance, _imageUrl, _houseType, _houseNo),
            owner: msg.sender
        });

        houseIds.push(_houseNo);

        emit FlatHouseAdded(_houseNo, _sellerAadhaar, _houseType, _rent, _advance);
    }

    function getFlatHouse(string memory _houseNo) public view returns (FlatHouse memory) {
        return flats[_houseNo];
    }

    function getAllFlatHouses() public view returns (FlatHouse[] memory) {
        FlatHouse[] memory allFlats = new FlatHouse[](houseIds.length);
        for (uint i = 0; i < houseIds.length; i++) {
            allFlats[i] = flats[houseIds[i]];
        }
        return allFlats;
    }
}

